function scrollHeader(){const e=document.querySelector("#header");let s=window.scrollY;function r(){s=window.scrollY,s>=1?e.classList.add("scrolling"):e.classList.remove("scrolling")}r(),window.addEventListener("scroll",r)}function mobileNav(){const e=document.querySelectorAll(".burger"),s=document.querySelector(".header__mob");e.forEach((e=>{e.addEventListener("click",(()=>{s.classList.toggle("active")}))})),s.addEventListener("click",(()=>{s.classList.remove("active")}))}function initCoverSlider(){$(document).ready((function(){$(".slider").slick({infinite:!0,autoplay:!0,speed:500,slidesToShow:1,slidesToScroll:1,arrows:!1,dots:!0,vertical:!0,verticalSwiping:!0})}))}function initProductsSlider(){$(document).ready((function(){$(".popular-products__slider").slick({infinite:!0,autoplay:!0,autoplaySpeed:1,speed:6e3,slidesToScroll:3,arrows:!0,dots:!1,variableWidth:!0,prevArrow:"<div class='arr-l arr'><img src='../images/popular-products/arr-l.svg'/></div>",nextArrow:"<div class='arr-r arr'><img src='../images/popular-products/arr-r.svg'/></div>"})})),$(".question__title").click((function(e){e.preventDefault();var s=$(this);s.next().hasClass("show")?(s.next().removeClass("show"),s.next().slideUp(350),s.removeClass("open")):(s.parent().parent().find("li .question__answer").removeClass("show"),s.parent().parent().find("li a").removeClass("open"),s.parent().parent().find("li .question__answer").slideUp(350),s.next().toggleClass("show"),s.next().slideToggle(350),s.toggleClass("open"))})),$(document).ready((function(){$(".main-slider").slick({slidesToShow:1,slidesToScroll:1,arrows:!0,fade:!0,asNavFor:".thumbnail-slider"}),$(".thumbnail-slider").slick({slidesToShow:6,slidesToScroll:1,asNavFor:".main-slider",dots:!1,centerMode:!0,focusOnSelect:!0,variableWidth:!0})}))}window.addEventListener("DOMContentLoaded",(()=>{scrollHeader(),mobileNav(),initCoverSlider(),initProductsSlider()}));